INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-1c87f27b-moex-00208', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '下列選項前後對話，成語使用最適當的是：', '["「令尊年高八十，猶然老當益壯。」／「家父身手靈活，真是一馬當先。」", "「貴公司業績能逆勢成長，可賀！可賀！」／「這全仰賴大家上下一心。」", "「你家屋內整理得光耀門楣，真是好看。」／「這一切，都是拙荊的心血。」", "「令公子金榜題名，真是蓬蓽生輝！」／「過獎！過獎！小兒不過是班門弄斧。」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00209', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「上個世紀結束後我再次離開美濃。當我在困頓、漂泊的午夜中神遊我莊、回顧自我， 慢慢發現，其實我莊植長在我身體之中，有時甚至就坐在額頭，左右了我人生的轉 彎。而且，它是我理解世界的第一個版本，往後的無數次增修，都將依之據之。」 根據上文，有關作者對「我莊」的敘述，最適當的是：', '["近鄉情怯，離家多年後再次返家，對於「我莊」益發思念", "雖遊歷世界多處，但始終未曾發現比「我莊」更美的地方", "曾在離家後的困頓之際想起「我莊」，進而反思其真正涵義", "時時惦記「我莊」，並藉由遠行經驗多次修改「我莊」形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00210', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「東方繪畫為主的中國花鳥畫，自古即在其象徵意義上，有更明確的發揮，比如以花 卉為寄寓，作為理想人格的投映。」 下列選項，何者最能呼應上文所述？', '["人面不知何處去，桃花依舊笑春風", "花謝花飛飛滿天，紅消香斷有誰憐", "竹外桃花三兩枝，春江水暖鴨先知", "莫嫌老圃秋容淡，且看黃花晚節香"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00211', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '行文表述時，合宜地運用正向思維與負向思維，接續排列文句，可達到顛覆與反轉 的趣味。如同曾任英國首相的邱吉爾名言：「你有敵人？很好！那說明在你人生中， 你曾為某些事堅持過。」即是善用了「先負轉正」的敘述方式。 下列那個句子的敘述方式最接近上文例句表述的方式？', '["生命是一襲華美的袍，爬滿了蝨子", "你在黑夜獨行，堅定地走出一路山明水秀", "先要了解事實，然後你才能夠隨心所欲的扭曲誤解它", "這個世界如此美好，值得人們為它奮鬥，我只同意後半句"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00212', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「凡是好人都樂於助人。小郭常常幫助別人，所以小郭是個好人。」以上的推論無效， 因為小郭常助人，可能別有所圖。下列何者也是這種無效的推論？', '["唯有正直的人是君子，所以不正直的人肯定不是君子", "唯有積極踏實者能成功，所以成功者都是積極踏實的", "凡是人都需要飲食。機器人不必飲食，所以機器人不是人", "凡是大丈夫都能屈能伸。阿德能屈能伸，所以阿德是大丈夫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00213', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '齊莊公出獵，有一蟲舉足將搏其輪。問其御曰：「此何蟲也？」對曰：「此所謂螳螂 者也。其為蟲也，知進而不知卻，不量力而輕敵。」莊公曰：「此為人，而必為天下 勇武矣！」迴車而避之，勇武聞之，知所盡死矣。（《淮南子》） 根據上文，齊莊公迴車而避之造成的結果是：', '["不與勇武之士衝突", "勇武之士無所畏懼", "勇武之士欲求明主", "不必遠求勇武之士"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00214', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「沒有嚐過窮苦，不懂得安逸的好處；沒有感到人生的寂寞，不能了解真愛的價值。 同樣地，未曾有過經驗的孺子，難以了解天真之可貴；老年人所以會和藹可親，也 是因為曾受過了經驗的洗禮。必定要對於人世上萬物萬事全看淡了，然後對於一二 件東西的留戀才會倍見真摯動人。」 根據上文，下列選項何者最接近文意？', '["甘將泥尾隨龜後，尚有雲心在鶴前", "獨當春盡情何限，尚有秋期別未遙", "存亡慣見渾無淚，鄉井難忘尚有心", "群山萬壑赴荊門，生長明妃尚有村"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00215', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「這並不是說，我想像自己的死不會給人留下遺憾：訃告無疑是會有的；但是，儘管 有哀悼——我並不否認這一點——我看到他人的生活照樣繼續著，依然如故；我看 到他們一如既往地忙於自己的事務，孜孜於他們的消遣，糾纏於他們的煩惱，光顧 同樣的場所、同樣的朋友；一切照舊，任什麼都改變不了他們的生存。」 根據上文，下列選項何者最接近作者對生死的感受？', '["重於泰山，輕於鴻毛", "安時處順，樂在其中", "生不足樂，死不足悲", "淡泊明志，寧靜致遠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00216', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '「世界聽障者的人數到2025年將達到9億人，其中因老化引發的傳音性聽障可透過 助聽器改善，但這些老人使用助聽器比率不高，主因為羞於戴助聽器、周圍聲音也 被擴大，以及操作不易等。他們若不用助聽器，與人溝通時則需要提高聲量，猶如 吵架氛圍，容易引發心理不適，減低交流意願。經研究1000Hz以上的周波數帶， 是言語明瞭度的關鍵，但是此周波數帶的聽力隨著老化而下降，可聽到聲音，但不 清晰。日人中石真一路開發『助聽喇叭』，以蜂巢板的喇叭增強高音域，並使音箱細 長化，鳴音部向後垂，便可『調強』1700Hz周波數，讓人聲清晰化，即可幫助輕度 聽障者。有別於傳統助聽器只是『擴大』所有聲音，助聽喇叭改善助聽器之不清晰、 不舒適的問題。過去的社會是聽障者配合健聽者戴『助聽器』；在合乎人性之『無障 礙環境規畫』時代，健聽者以『助聽喇叭』主動接近聽障者，成就無障礙之傾聽交 流環境，是文明社會的指標之一。」 有關因老化引發傳音性聽障的敘述，下列選項何者最符合文意？', '["改善的最好方式是配戴助聽器", "未積極改善容易產生心理相關問題", "形成的主因是無法辨別1700Hz周波數的子音", "老化的大腦無法將聲音轉化成可辨識的語言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00217', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-112-13504c0c', 'sub-diplomatic-1c87f27b-01', NULL, 'single_choice', '承上題，關於助聽喇叭的研發與使用，下列選項何者最不符合本文意旨？', '["助聽器的設計著重於處理音質問題，而助聽喇叭則著重於改善音量問題", "健聽者以「助聽喇叭」主動接近聽障者，可成就無障礙之傾聽交流環境", "公私部門的服務窗口，宜增設助聽喇叭，有助形塑無形的「無障礙空間」", "「助聽喇叭」的設計理念更合乎聽障者需求，可說是文明社會的指標之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:00+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL)
